1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with 3 neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
19	  it.todo("should bring a dead cell to life with exactly 3 neighbors (reproduction)");
20	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
21	  it.todo("should keep a 2x2 block as a still life");
22	  it.todo("should handle cells with negative coordinates");
23	});
